function buildOpening(def) {
  const game = new Chess();
  const moves = def.line.map(([san, explanation]) => {
    const result = game.move(san);
    if (!result) throw new Error(`Illegal move ${san} in ${def.id}`);
    return { san: result.san, explanation, fen: game.fen() };
  });
  // Sanity: the line must end on the player's own move so the trainer completes
  // on a player action (opponent moves auto-play).
  const lastColor = game.history({ verbose: true }).slice(-1)[0].color === 'w' ? 'white' : 'black';
  if (lastColor !== def.color) {
    throw new Error(`${def.id}: line ends on ${lastColor} move but opening color is ${def.color}`);
  }
  return moves;
}

function serialize(def, moves) {
  const movesSrc = moves
    .map(
      (m) =>
        `    {\n      san: ${JSON.stringify(m.san)},\n      explanation:\n        ${JSON.stringify(
          m.explanation
        )},\n      fen: ${JSON.stringify(m.fen)},\n    },`
    )
    .join('\n');
  const principlesSrc = def.principles.map((p) => `    ${JSON.stringify(p)},`).join('\n');
  return `import type { Opening } from '@/types';

export const ${def.exportName}: Opening = {
  id: ${JSON.stringify(def.id)},
  name: ${JSON.stringify(def.name)},
  color: ${JSON.stringify(def.color)},
  eco: ${JSON.stringify(def.eco)},
  description:
    ${JSON.stringify(def.description)},
  keyPrinciples: [
${principlesSrc}
  ],
  moves: [
${movesSrc}
  ],
};
`;
}

const generated = [];
for (const def of openings) {
  const moves = buildOpening(def);
  const src = serialize(def, moves);
  const file = join(outDir, `${def.id}.ts`);
  writeFileSync(file, src);
  generated.push(def);
  console.log(`wrote ${def.id}.ts (${moves.length} moves, ends on ${def.color})`);
}

console.log('\nAll openings generated and FEN-verified.');
